+    assert!(svc.get_status("svc.A").is_none());
+    assert!(svc.get_status("svc.B").is_some());
+
+    // Clear all
+    svc.clear();
+    assert!(svc.services().is_empty());
+
+    test_complete!("grpc_verify_024_health_service_lifecycle");
