+
+    struct DoubleService;
+
+    impl AsupersyncService<i32> for DoubleService {
+        type Response = i32;
+        type Error = std::convert::Infallible;
+
+        async fn call(&self, _cx: &Cx, request: i32) -> Result<Self::Response, Self::Error> {
+            Ok(request * 2)
+        }
+    }
